        self.app_log_file = os.path.join(self.log_dir, f"{app_name}.log")
        self.error_log_file = os.path.join(self.log_dir, f"{app_name}_error.log")
        self.audit_log_file = os.path.join(self.log_dir, f"{app_name}_audit.log")

